  buildMessage msg =
    (if msg.sampleStackIndex == 0 then mempty else archVarint 8 (fromIntegral msg.sampleStackIndex))
    <> encodePackedInt32 2 msg.sampleAttributeIndices
    <> (if msg.sampleLinkIndex == 0 then mempty else archVarint 24 (fromIntegral msg.sampleLinkIndex))
    <> encodePackedInt64 4 msg.sampleValues
    <> encodePackedFixed64 5 msg.sampleTimestampsUnixNano
    <> encodeUnknownFields msg.sampleUnknownFields

instance MessageSize Sample where
  messageSize msg =
    (if msg.sampleStackIndex == 0 then 0 else archVarintSize (fromIntegral msg.sampleStackIndex))
    + (let pl = VU.foldl' (\a v -> a + varintSize (fromIntegral v)) 0 msg.sampleAttributeIndices in if pl == 0 then 0 else tagSize 2 + varintSize (fromIntegral pl) + pl)
    + (if msg.sampleLinkIndex == 0 then 0 else archVarintSize (fromIntegral msg.sampleLinkIndex))
    + (let pl = VU.foldl' (\a v -> a + varintSize (fromIntegral v)) 0 msg.sampleValues in if pl == 0 then 0 else tagSize 4 + varintSize (fromIntegral pl) + pl)
    + (let n = VU.length msg.sampleTimestampsUnixNano in if n == 0 then 0 else tagSize 5 + varintSize (fromIntegral (n * 8)) + n * 8)
    + unknownFieldsSize msg.sampleUnknownFields

