  {-# INLINE messageDecoder #-}
  messageDecoder = loop 0 VU.empty 0 VU.empty VU.empty []
    where
      loop acc_0 acc_1 acc_2 acc_3 acc_4 acc_unknown_ = withTagM
        (pure (Sample {sampleStackIndex = acc_0, sampleAttributeIndices = acc_1, sampleLinkIndex = acc_2, sampleValues = acc_3, sampleTimestampsUnixNano = acc_4, sampleUnknownFields = reverse acc_unknown_}))
        (\fn wt -> case fn of
          1 -> do
            v <- (fromIntegral <$> decodeFieldVarint)
            loop v acc_1 acc_2 acc_3 acc_4 acc_unknown_
          2 -> case wt of
            2 -> do
