              loop acc_0 acc_1 acc_2 acc_3 (acc_4 <> vs) acc_unknown_
            _ -> do
              v <- decodeFieldFixed64
              loop acc_0 acc_1 acc_2 acc_3 (acc_4 <> VU.singleton v) acc_unknown_
          _ -> do
            uf <- captureUnknownField fn (toEnum wt)
            loop acc_0 acc_1 acc_2 acc_3 acc_4 (uf : acc_unknown_))

