    <> (if msg.locationAddress == 0 then mempty else archVarint 16 msg.locationAddress)
    <> V.foldl' (\acc v -> let sz = messageSize v in acc <> archSubmessage 26 sz (buildMessage v)) mempty msg.locationLines
    <> encodePackedInt32 4 msg.locationAttributeIndices
    <> encodeUnknownFields msg.locationUnknownFields

